import { cache } from "react";

import { sampleSettings, sampleSnapshots, sampleTrades } from "@/lib/sample-data";
import { calculatePerformanceStats, isTradeClosed, isTradeOpen } from "@/lib/trade-math";
import { createServerSupabaseClient } from "@/lib/supabase/server";
import type {
  AdminModelData,
  EquitySnapshotRow,
  PublicModelData,
  SettingsRow,
  TradeRow,
} from "@/lib/types";
import { isSupabaseConfigured } from "@/lib/utils";

function sortTradesDescending(trades: TradeRow[], field: "opened_at" | "closed_at") {
  return [...trades].sort(
    (left, right) =>
      new Date(right[field] ?? right.opened_at).getTime() -
      new Date(left[field] ?? left.opened_at).getTime(),
  );
}

function buildModelData(input: {
  settings: SettingsRow;
  trades: TradeRow[];
  snapshots: EquitySnapshotRow[];
  previewMode: boolean;
}): PublicModelData {
  const openTrades = sortTradesDescending(input.trades.filter(isTradeOpen), "opened_at");
  const closedTrades = sortTradesDescending(input.trades.filter(isTradeClosed), "closed_at");
  const { stats, equityCurve } = calculatePerformanceStats({
    settings: input.settings,
    openTrades,
    closedTrades,
    snapshots: input.snapshots,
  });

  return {
    settings: input.settings,
    openTrades,
    closedTrades,
    latestClosedTrades: closedTrades.slice(0, 6),
    latestOpenTrades: openTrades.slice(0, 4),
    stats,
    equityCurve,
    snapshots: input.snapshots,
    previewMode: input.previewMode,
  };
}

export const getPublicModelData = cache(async (): Promise<PublicModelData> => {
  if (!isSupabaseConfigured()) {
    return buildModelData({
      settings: sampleSettings,
      trades: sampleTrades,
      snapshots: sampleSnapshots,
      previewMode: true,
    });
  }

  const supabase = await createServerSupabaseClient();
  const [settingsResponse, tradesResponse, snapshotsResponse] = await Promise.all([
    supabase
      .from("settings")
      .select("*")
      .order("created_at", { ascending: true })
      .limit(1)
      .maybeSingle(),
    supabase.from("trades").select("*").order("opened_at", { ascending: false }),
    supabase
      .from("equity_snapshots")
      .select("*")
      .order("snapshot_date", { ascending: true }),
  ]);

  if (settingsResponse.error) {
    throw new Error(settingsResponse.error.message);
  }

  if (tradesResponse.error) {
    throw new Error(tradesResponse.error.message);
  }

  if (snapshotsResponse.error) {
    throw new Error(snapshotsResponse.error.message);
  }

  const settings = (settingsResponse.data as SettingsRow | null) ?? sampleSettings;
  const trades = (tradesResponse.data as TradeRow[]) ?? [];
  const snapshots = snapshotsResponse.data ?? [];

  return buildModelData({
    settings,
    trades,
    snapshots,
    previewMode: false,
  });
});

export async function getAdminModelData(input: {
  editTradeId?: string;
  closeTradeId?: string;
}): Promise<AdminModelData> {
  const data = await getPublicModelData();

  return {
    ...data,
    selectedTrade:
      data.openTrades.find((trade) => trade.id === input.editTradeId) ??
      data.closedTrades.find((trade) => trade.id === input.editTradeId) ??
      null,
    closeTrade:
      data.openTrades.find((trade) => trade.id === input.closeTradeId) ?? null,
  };
}
